class MethodChannelPaymentGatewayAdapter implements PaymentGatewayAdapter {
  final MethodChannel _channel;
  final String providerName;

  MethodChannelPaymentGatewayAdapter(this.providerName)
      : _channel = MethodChannel('com.example.payment/$providerName');

  @override
  Future<void> initialize({required Map<String, dynamic> config}) async {
    try {
      await _channel.invokeMethod<void>('initialize', {'config': config});
    } on PlatformException catch (e) {
      throw PaymentException(e.message ?? 'Initialization failed', code: e.code, details: e.details);
    }
  }

  @override
  Future<PaymentResult> process(PaymentRequest request) async {
    try {
      final result = await _channel.invokeMethod<Map<dynamic, dynamic>>('process', {'request': request.toJson()});
      return _mapResult(result);
    } on PlatformException catch (e) {
      throw PaymentException(e.message ?? 'Payment failed', code: e.code, details: e.details);
    }
  }

  @override
  Future<PaymentResult> restorePurchases() async {
    try {
      final result = await _channel.invokeMethod<Map<dynamic, dynamic>>('restorePurchases');
      return _mapResult(result);
    } on PlatformException catch (e) {
      throw PaymentException(e.message ?? 'Restore failed', code: e.code, details: e.details);
    }
  }

  @override
  Future<PaymentResult> confirmServerSide({required String providerReference, required Map<String, dynamic> payload}) async {
    try {
      final result = await _channel.invokeMethod<Map<dynamic, dynamic>>(
        'confirmServerSide',
        {'providerReference': providerReference, 'payload': payload},
      );
      return _mapResult(result);
    } on PlatformException catch (e) {
      throw PaymentException(e.message ?? 'Server confirmation failed', code: e.code, details: e.details);
    }
  }

  @override
  Future<void> dispose() async {
    try {
      await _channel.invokeMethod<void>('dispose');
    } catch (_) {}
  }

  PaymentResult _mapResult(Map<dynamic, dynamic>? map) {
    if (map == null) {
      return PaymentResult(status: PaymentStatus.failed, message: 'Empty response', timestamp: DateTime.now());
    }
    return PaymentResult.fromJson(Map<String, dynamic>.from(map.cast<dynamic, dynamic>()));
  }
}

class PaymentSecurity {
  static String maskSensitive(String value) {
    if (value.length <= 4) return '*' * value.length;
    return '${'*' * (value.length - 4)}${value.substring(value.length - 4)}';
  }

  static Map<String, dynamic> sanitizeLogPayload(Map<String, dynamic> payload) {
    final copy = Map<String, dynamic>.from(payload);
    const sensitiveKeys = {
      'cardNumber',
      'cvv',
      'cvc',
      'pin',
      'password',
      'token',
      'secret',
      'accessToken',
      'refreshToken',
      'paymentMethodId',
      'nonce',
    };
    for (final key in copy.keys.toList()) {
      final val = copy[key];
      if (sensitiveKeys.contains(key) && val is String) {
        copy[key] = maskSensitive(val);
      } else if (val is Map<String, dynamic>) {
        copy[key] = sanitizeLogPayload(val);
      }
    }
    return copy;
  }

  static bool isValidCurrency(String currency) => RegExp(r'^[A-Z]{3}$').hasMatch(currency);

  static bool isValidAmount(double amount) => amount > 0 && amount.isFinite;

  static String generateClientTransactionId(String orderId) {
    final ts = DateTime.now().microsecondsSinceEpoch;
    return 'txn_${orderId}_$ts';
  }
}

class PaymentClient extends ChangeNotifier {
  final Map<PaymentProvider, PaymentGatewayAdapter> _adapters;
  final Map<PaymentProvider, Map<String, dynamic>> _configs;
  final StreamController<PaymentResult> _eventsController = StreamController<PaymentResult>.broadcast();

  PaymentStatus _status = PaymentStatus.idle;
  PaymentStatus get status => _status;

  Stream<PaymentResult> get events => _eventsController.stream;

  PaymentClient({
    Map<PaymentProvider, PaymentGatewayAdapter>? adapters,
    Map<PaymentProvider, Map<String, dynamic>>? configs,
  })  : _adapters = adapters ?? {
          PaymentProvider.stripe: MethodChannelPaymentGatewayAdapter('stripe'),
          PaymentProvider.paypal: MethodChannelPaymentGatewayAdapter('paypal'),
          PaymentProvider.inAppPurchase: MethodChannelPaymentGatewayAdapter('in_app_purchase'),
          PaymentProvider.applePay: MethodChannelPaymentGatewayAdapter('apple_pay'),
          PaymentProvider.googlePay: MethodChannelPaymentGatewayAdapter('google_pay'),
          PaymentProvider.wallet: MethodChannelPaymentGatewayAdapter('wallet'),
        },
        _configs = configs ?? const {};

  Future<void> initialize({Set<PaymentProvider>? providers}) async {
    _setStatus(PaymentStatus.initializing);
    final targets = providers ?? _adapters.keys.toSet();
    for (final provider in targets) {
      final adapter = _adapters[provider];
      if (adapter == null) continue;
      await adapter.initialize(config: _configs[provider] ?? const {});
    }
    _setStatus(PaymentStatus.ready);
  }

  Future<PaymentResult> processPayment(PaymentRequest request) async {
    _validateRequest(request);
    final adapter = _adapters[request.provider];
    if (adapter == null) throw PaymentException('Unsupported provider: ${describeEnum(request.provider)}');
    _setStatus(PaymentStatus.processing);
    final result = await adapter.process(request);
    _emit(result);
    _setStatus(result.status);
    return result;
  }

  Future<PaymentResult> restorePurchases(PaymentProvider provider) async {
    final adapter = _adapters[provider];
    if (adapter == null) throw PaymentException('Unsupported provider: ${describeEnum(provider)}');
    _setStatus(PaymentStatus.processing);
    final result = await adapter.restorePurchases();
    _emit(result);
    _setStatus(result.status);
    return result;
  }

  Future<PaymentResult> confirmServerSide({
    required PaymentProvider provider,
    required String providerReference,
    required Map<String, dynamic> payload,
  }) async {
    final adapter = _adapters[provider];
    if (adapter == null) throw PaymentException('Unsupported provider: ${describeEnum(provider)}');
    final result = await adapter.confirmServerSide(providerReference: providerReference, payload: payload);
    _emit(result);
    _setStatus(result.status);
    return result;
  }

  Future<void> disposeClient() async {
    for (final adapter in _adapters.values) {
      await adapter.dispose();
    }
    await _eventsController.close();
  }

  void _validateRequest(PaymentRequest request) {
    if (!PaymentSecurity.isValidAmount(request.amount)) {
      throw PaymentException('Invalid amount');
    }
    if (!PaymentSecurity.isValidCurrency(request.currency)) {
      throw PaymentException('Invalid currency');
    }
    if (request.orderId.trim().isEmpty) {
      throw PaymentException('orderId is required');
    }
    if (request.description.trim().isEmpty) {
      throw PaymentException('description is required');
    }
  }

  void _setStatus(PaymentStatus status) {
    _status = status;
    notifyListeners();
  }

  void _emit(PaymentResult result) {
    if (!_eventsController.isClosed) {
      _eventsController.add(result);
    }
  }
}

